#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,v,t;
    double k;
    bool operator<(const node&b)const
    {
        return k<b.k;
    }
}a[10010];
int n,m,f,fa[410];
const double eps=(1e-9);
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
bool check(double x)
{
    double ans=0;
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        a[i].k=x*a[i].t+1.0*a[i].v;
    }
    sort(a+1,a+1+m);
    for(int i=1;i<=m;i++)
    {
        if(find(a[i].x)!=find(a[i].y))
        {
            ans+=a[i].k;
            fa[find(a[i].x)]=find(a[i].y);
        }
    }
    return !(f>ans);
}
int main()
{
    scanf("%d%d%d",&n,&m,&f);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d%d",&a[i].x,&a[i].y,&a[i].v,&a[i].t);
    }
    if(check(0))
    {
        printf("0.0000");
        return 0;
    }
    double l=0,r=1e14;
    while(r-l>eps)
    {
        double mid=(l+r)/2;
        if(check(mid))
        {
            r=mid-eps;
        }
        else
        {
            l=mid+eps;
        }
    }
    printf("%.4lf",l);
    return 0;
}
